import{c as i,Q as e,j as s,m as t}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"SOP-001: Instalacija & Setup Vodič","description":"Vodič za konfigurisanje i prvo pokretanje sistema AI Workflow Orchestrator","frontmatter":{"title":"SOP-001: Instalacija & Setup Vodič","description":"Vodič za konfigurisanje i prvo pokretanje sistema AI Workflow Orchestrator","keywords":"installation guide, environment setup, python uvicorn, api rotation, key manager, mongodb setup","robots":"index, follow"},"headers":[],"relativePath":"sop/setup.md","filePath":"sop/setup.md","lastUpdated":null}'),n={name:"sop/setup.md"};function o(r,a,l,p,h,d){return e(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="🛠️-sop-001-instalacija-setup-vodic" tabindex="-1">🛠️ SOP-001: Instalacija &amp; Setup Vodič <a class="header-anchor" href="#🛠️-sop-001-instalacija-setup-vodic" aria-label="Permalink to &quot;🛠️ SOP-001: Instalacija &amp; Setup Vodič&quot;">​</a></h1><p>Ovaj operativni priručnik (Runbook) obezbeđuje sveobuhvatne korake za instalaciju zavisnosti, konfigurisanje modela, rotaciju API ključeva i bezbedno pokretanje <strong>AI Workflow Orchestrator</strong> sistema.</p><hr><h2 id="📋-1-preduslovi-i-sistemski-zahtevi" tabindex="-1">📋 1. Preduslovi i Sistemski Zahtevi <a class="header-anchor" href="#📋-1-preduslovi-i-sistemski-zahtevi" aria-label="Permalink to &quot;📋 1. Preduslovi i Sistemski Zahtevi&quot;">​</a></h2><p>Sistem zahteva sledeće komponente instalirane na host mašini:</p><ul><li><strong>OS:</strong> Linux (Ubuntu 20.04+ preporučeno) ili macOS.</li><li><strong>Python verzija:</strong> <code>3.10</code> ili novija (kompatibilno sa <code>3.11</code>).</li><li><strong>Slobodan prostor:</strong> Minimalno <code>500MB</code> slobodnog prostora za traces i SQLite bazu podataka.</li></ul><hr><h2 id="💾-2-kloniranje-i-instalacija-zavisnosti" tabindex="-1">💾 2. Kloniranje i Instalacija Zavisnosti <a class="header-anchor" href="#💾-2-kloniranje-i-instalacija-zavisnosti" aria-label="Permalink to &quot;💾 2. Kloniranje i Instalacija Zavisnosti&quot;">​</a></h2><p>Pratite sledeće korake za preuzimanje repozitorijuma i instalaciju paketa:</p><ol><li><p><strong>Klonirajte repozitorijum:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/kiza101288/ai-workflow-orchestrator.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai-workflow-orchestrator</span></span></code></pre></div></li><li><p><strong>Kreirajte i aktivirajte virtuelno okruženje:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv/bin/activate</span></span></code></pre></div></li><li><p><strong>Instalirajte Python pakete:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --upgrade</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pip</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> requirements.txt</span></span></code></pre></div></li></ol><hr><h2 id="🔑-3-podesavanje-api-kljuceva-i-rotacija" tabindex="-1">🔑 3. Podešavanje API Ključeva i Rotacija <a class="header-anchor" href="#🔑-3-podesavanje-api-kljuceva-i-rotacija" aria-label="Permalink to &quot;🔑 3. Podešavanje API Ključeva i Rotacija&quot;">​</a></h2><p>Sistem koristi napredni <strong>KeyManager</strong> za upravljanje Gemini API ključevima. U slučaju prekoračenja limita (Rate Limit - HTTP 429), KeyManager automatski detektuje blokadu, privremeno uklanja neispravan ključ i rotira na sledeći dostupan ključ iz liste.</p><h3 id="konfigurisanje-kljuceva-preko-env-varijabli" tabindex="-1">Konfigurisanje ključeva preko Env varijabli: <a class="header-anchor" href="#konfigurisanje-kljuceva-preko-env-varijabli" aria-label="Permalink to &quot;Konfigurisanje ključeva preko Env varijabli:&quot;">​</a></h3><p>Prosledite ključeve kao listu odvojenu zarezima u env promenljivoj <code>GOOGLE_API_KEY</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GOOGLE_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;AIzaSyA1...,AIzaSyA2...,AIzaSyA3...&quot;</span></span></code></pre></div><p>KeyManager u [key_manager.py](file:///home/kizabgd/.gemini/extensions/ai-workflow-orchestrator/core/key_manager.py) će automatski parsirati ove ključeve i rotirati ih po &quot;round-robin&quot; principu tokom rada agenata.</p><hr><h2 id="☁️-4-integracija-mongodb-atlas-memorije" tabindex="-1">☁️ 4. Integracija MongoDB Atlas Memorije <a class="header-anchor" href="#☁️-4-integracija-mongodb-atlas-memorije" aria-label="Permalink to &quot;☁️ 4. Integracija MongoDB Atlas Memorije&quot;">​</a></h2><p>Za dugoročno forenzičko pamćenje i vektorsku pretragu sličnih konflikata, orkestrator koristi MongoDB Atlas.</p><ol><li><strong>Preuzmite MongoDB URI iz Atlas konzole</strong> (obezbedite da je dozvoljena IP adresa kontejnera u Network Access sekciji).</li><li><strong>Postavite env varijablu:</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> MONGODB_URI</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mongodb+srv://&lt;korisnik&gt;:&lt;lozinka&gt;@cluster.mongodb.net/?retryWrites=true&amp;w=majority&quot;</span></span></code></pre></div></li><li><strong>Podešavanje baze i kolekcija:</strong> Naziv baze u kodu je definisan kao <code>ai_workflow_orchestrator</code>. Prilikom prve konekcije, MongoDBMemory klasa će automatski kreirati indekse na kolekcijama <code>debates</code>, <code>arguments</code> i <code>decision_history</code>.</li></ol><p><em>Ukoliko <code>MONGODB_URI</code> nije definisan ili mrežna konekcija ne uspe, sistem se bezbedno prebacuje na lokalnu SQLite bazu na putanji <code>storage/memory.db</code>.</em></p><hr><h2 id="🔒-5-zaobilazenje-identity-provere-u-netipicnim-sredinama" tabindex="-1">🔒 5. Zaobilaženje Identity Provere u Netipičnim Sredinama <a class="header-anchor" href="#🔒-5-zaobilazenje-identity-provere-u-netipicnim-sredinama" aria-label="Permalink to &quot;🔒 5. Zaobilaženje Identity Provere u Netipičnim Sredinama&quot;">​</a></h2><p>Nulti-stepeni <code>IdentityGuard</code> u <code>core/identity.py</code> po defaultu zahteva da vrednost varijable <code>GOOGLE_CLOUD_PROJECT</code> bude <code>sixth-hawk-492717-m1</code> i <code>MONGODB_DATABASE</code> bude <code>ai_workflow_orchestrator</code>.</p><p>Ako sistem pokrećete u lokalnom test okruženju ili na javnoj demonstraciji (npr. Hugging Face Spaces), identity provera će zaustaviti proces. Da biste je bezbedno zaobišli, postavite env flag:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SKIP_IDENTITY_CHECK</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">true</span></span></code></pre></div><hr><h2 id="🏃-6-pokretanje-sistema" tabindex="-1">🏃 6. Pokretanje Sistema <a class="header-anchor" href="#🏃-6-pokretanje-sistema" aria-label="Permalink to &quot;🏃 6. Pokretanje Sistema&quot;">​</a></h2><p>Sistem nudi dva načina pokretanja:</p><h3 id="a-pokretanje-preko-cli-ja-komandna-linija" tabindex="-1">A) Pokretanje preko CLI-ja (Komandna Linija) <a class="header-anchor" href="#a-pokretanje-preko-cli-ja-komandna-linija" aria-label="Permalink to &quot;A) Pokretanje preko CLI-ja (Komandna Linija)&quot;">​</a></h3><p>Za izvršavanje pojedinačnog zahteva uz kompletnu adversarial debatu i ispis trace-a u terminalu:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;deploy a secure database cluster on GKE&quot;</span></span></code></pre></div><h3 id="b-pokretanje-api-ja-i-web-dashboard-a" tabindex="-1">B) Pokretanje API-ja i Web Dashboard-a <a class="header-anchor" href="#b-pokretanje-api-ja-i-web-dashboard-a" aria-label="Permalink to &quot;B) Pokretanje API-ja i Web Dashboard-a&quot;">​</a></h3><p>Za pokretanje FastAPI servera koji poslužuje Glassmorphism dashboard na portu <code>7860</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uvicorn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api.routes:app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --host</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.0.0.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 7860</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reload</span></span></code></pre></div><p>Nakon pokretanja, otvorite brauzer na <code>http://localhost:7860</code> kako biste pristupili premium dashboardu sa real-time vizuelizacijom debate i trace-ova.</p>`,37)])])}const u=i(n,[["render",o]]);export{c as __pageData,u as default};
